import { z } from 'zod';

// Define the environment schema using Zod
const envSchema = z.object({
  PORT: z.string().regex(/^[0-9]+$/).transform(Number),
  NODE_ENV: z.enum(['development', 'production', 'test']),
  JWT_SECRET: z.string().min(32),
  RATE_LIMIT_MAX: z.string().regex(/^[0-9]+$/).transform(Number),
  RATE_LIMIT_WINDOW: z.string().regex(/^[0-9]+$/).transform(Number),
  CORS_ORIGIN: z.string().optional(),
});

// Validate the environment variables
export const env = envSchema.parse(process.env);

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';
import { env } from '../config/env';

export const securityMiddleware = [
  helmet(),
  cors({
    origin: env.CORS_ORIGIN,
  }),
  rateLimit({
    windowMs: env.RATE_LIMIT_WINDOW * 1000, // seconds to milliseconds
    max: env.RATE_LIMIT_MAX,
    message: 'Too many requests, please try again later.',
    headers: true,
  }),
];

import { Request, Response, NextFunction } from 'express';
import { Logger } from '../utils/logger';

export const errorHandler = (
  err: Error,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  Logger.error({ message: err.message, stack: err.stack, requestId: req.id });
  res.status(500).json({ error: 'Internal Server Error', requestId: req.id });
};

import { createLogger, format, transports } from 'winston';

export const Logger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.printf(({ timestamp, level, message, requestId }) => {
      return `${timestamp} [${level}] [${requestId || 'N/A'}]: ${message}`;
    })
  ),
  transports: [new transports.Console()],
});

export class BaseDTO<T> {
  constructor(partial: Partial<T>) {
    Object.assign(this, partial);
  }
}
